import{_ as a,o as r,c as l,a2 as i}from"./chunks/framework.ZhLefgN8.js";const c=JSON.parse('{"title":"订单提交失败怎么办","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"troubleshooting/order-failure.md","filePath":"zh-CN/troubleshooting/order-failure.md"}'),e={name:"troubleshooting/order-failure.md"};function o(d,t,n,h,s,u){return r(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="订单提交失败怎么办" tabindex="-1">订单提交失败怎么办 <a class="header-anchor" href="#订单提交失败怎么办" aria-label="Permalink to &quot;订单提交失败怎么办&quot;">​</a></h1><p>下单时提示错误或订单无法提交，根据错误信息或现象定位原因。</p><h2 id="账户资金不足" tabindex="-1">账户资金不足 <a class="header-anchor" href="#账户资金不足" aria-label="Permalink to &quot;账户资金不足&quot;">​</a></h2><p>提示「资金不足」「余额不足」「Insufficient funds」：</p><ol><li>进入「资产」页面确认可用余额，注意区分币种（港元 / 美元）</li><li>如委托金额超出可用余额，降低数量或金额后重新下单</li><li>如账户有余额但仍提示不足：检查是否有其他订单占用了可用资金（已挂出的未成交买单会占用资金）</li><li>如需更多资金，通过入金或换汇补充</li></ol><h2 id="交易时间限制" tabindex="-1">交易时间限制 <a class="header-anchor" href="#交易时间限制" aria-label="Permalink to &quot;交易时间限制&quot;">​</a></h2><p>提示「市场已关闭」「非交易时段」：</p><table tabindex="0"><thead><tr><th>市场</th><th>正常交易时间</th></tr></thead><tbody><tr><td>港股（持续交易）</td><td>交易日 09:30–12:00，13:00–16:00（HKT）</td></tr><tr><td>港股竞价</td><td>开市竞价 09:00–09:20，收市竞价 16:00–16:10</td></tr><tr><td>美股（正式时段）</td><td>美东 09:30–16:00</td></tr><tr><td>美股盘前</td><td>美东 04:00–09:30</td></tr><tr><td>美股盘后</td><td>美东 16:00–20:00</td></tr><tr><td>美股期权</td><td>美东 09:30–16:00（部分 ETF 期权至 16:15）</td></tr></tbody></table><p>港股盘前盘后暂不支持交易。如在交易时间内仍提示市场关闭，检查标的是否正在停牌或暂停交易。</p><h2 id="标的不支持或权限不足" tabindex="-1">标的不支持或权限不足 <a class="header-anchor" href="#标的不支持或权限不足" aria-label="Permalink to &quot;标的不支持或权限不足&quot;">​</a></h2><p>提示「该标的不支持交易」「权限不足」：</p><ul><li><strong>港股碎股</strong>：碎股只能使用「碎股单」类型，不支持市价单</li><li><strong>美股期权</strong>：确认账户已开通期权交易权限；部分流通性较低的期权合约暂不支持</li><li><strong>卖空</strong>：如提示无法卖空，确认该标的支持融券且账户已开通融资账户</li><li><strong>期权盘前</strong>：仅部分热门标的支持盘前期权交易，在期权链页面勾选「支持盘前交易」筛选</li></ul><h2 id="保证金不足-融资-期权卖方" tabindex="-1">保证金不足（融资 / 期权卖方） <a class="header-anchor" href="#保证金不足-融资-期权卖方" aria-label="Permalink to &quot;保证金不足（融资 / 期权卖方）&quot;">​</a></h2><p>提示「保证金不足」「Margin insufficient」：</p><ol><li>进入「资产」确认保证金使用率</li><li>降低订单数量，使保证金要求降至可用范围内</li><li>或先平仓部分持仓释放保证金后再下单</li></ol><p>如账户触发 Margin Call，新开仓可能被限制，需先补充资金或平仓。</p><h2 id="订单参数有误" tabindex="-1">订单参数有误 <a class="header-anchor" href="#订单参数有误" aria-label="Permalink to &quot;订单参数有误&quot;">​</a></h2><p>提示「价格超出范围」「最小手数」「委托数量无效」：</p><ul><li><strong>限价单价格偏离</strong>：港股限价单价格须在最新成交价的一定范围内（通常 ±24 个价格档位）；过高或过低的价格会被拒绝</li><li><strong>港股手数限制</strong>：整手订单数量须为一手的整数倍（如一手 100 股，则数量须为 100、200、300 等）</li><li><strong>最小金额</strong>：美股定投最低 10 美元；部分产品有最低委托金额要求</li></ul><h2 id="网络或系统问题" tabindex="-1">网络或系统问题 <a class="header-anchor" href="#网络或系统问题" aria-label="Permalink to &quot;网络或系统问题&quot;">​</a></h2><p>下单按钮无响应，或提示「提交失败」「网络错误」：</p><ol><li>检查网络连接，切换 Wi-Fi / 移动数据后重试</li><li>关闭 VPN 或代理后重试</li><li>强制重启 App 后重新下单</li><li>如问题持续，参阅 <a href="./APP网络连接排查">APP 网络连接排查</a></li></ol><h2 id="股票停牌或暂停交易" tabindex="-1">股票停牌或暂停交易 <a class="header-anchor" href="#股票停牌或暂停交易" aria-label="Permalink to &quot;股票停牌或暂停交易&quot;">​</a></h2><p>如标的正在停牌（港股 / 美股），系统会拒绝新订单直到复牌。可在标的详情页或公告中确认停牌状态。</p><h2 id="仍无法解决" tabindex="-1">仍无法解决 <a class="header-anchor" href="#仍无法解决" aria-label="Permalink to &quot;仍无法解决&quot;">​</a></h2><p>联系客服时提供：</p><ul><li>错误提示截图</li><li>标的代码（如 00700、AAPL）</li><li>订单类型、数量和价格</li></ul><p><strong>在线客服</strong>：长桥 App → 我的 → 帮助与客服 → 在线客服</p>',28)])])}const b=a(e,[["render",o]]);export{c as __pageData,b as default};
